import collections

def optimal_account_balancing(transactions):
    balances = collections.defaultdict(int)
    for payer, payee, amount in transactions:
        balances[payer] -= amount
        balances[payee] += amount

    givers = collections.deque()
    receivers = collections.deque()

    for person, amount in balances.items():
        if amount < 0:
            givers.append((person, -amount))
        elif amount > 0:
            receivers.append((person, amount))

    settlements = []

    while givers and receivers:
        giver_person, giver_amount = givers.popleft()
        receiver_person, receiver_amount = receivers.popleft()

        settle_amount = min(giver_amount, receiver_amount)

        settlements.append((giver_person, receiver_person, settle_amount))

        giver_remaining = giver_amount - settle_amount
        receiver_remaining = receiver_amount - settle_amount

        if giver_remaining > 0:
            givers.appendleft((giver_person, giver_remaining))
        if receiver_remaining > 0:
            receivers.appendleft((receiver_person, receiver_remaining))

    return settlements
